# Module providing mathematical utility functions and classes

class Calculator:
    name: str

    def __init__(self, name: str):
        self.name = name

    def add(self, a: int, b: int) -> int:
        return a + b

    def multiply(self, a: int, b: int) -> int:
        return a * b

def square(n: int) -> int:
    return n * n

def cube(n: int) -> int:
    return n * n * n

def is_even(n: int) -> bool:
    return n % 2 == 0

