# Module providing string manipulation utilities

def repeat_string(text: str, times: int) -> str:
    result: str = ""
    i: int = 0
    while i < times:
        result += text
        i += 1
    return result

def count_chars(text: str) -> int:
    count: int = 0
    for c in text:
        count += 1
    return count

class Formatter:
    prefix: str

    def __init__(self, prefix: str):
        self.prefix = prefix

    def format_message(self, msg: str) -> str:
        return f"{self.prefix}: {msg}"
